INSERT INTO reviews (uuid, name, body, stars, created_at) VALUES
('gr-001', 'CG Shower Doors And Mirrors', 'He probado muchas barberías en Cape Coral y casi siempre salía insatisfecho. Desde que abrió Next Level, soy cliente regular. El servicio es espectacular y el corte es el mejor que encontrarás en toda la ciudad. Lo recomiendo muchísimo.', 5, '2025-01-01T10:00:00.000Z'),
('gr-002', 'Jeff Nicholson PhD, PA-C', 'Jeffrey P me dio uno de los mejores cortes que he tenido. Líneas muy limpias, prolijas, no demasiado corto y bien combinado con el cabello más largo.', 5, '2025-01-05T10:00:00.000Z'),
('gr-003', 'gabrial luna', 'Yoni en stage 7 es el mejor barbero en mi opinión. Me encanta cómo me corta el pelo y muchos de mis amigos vienen con él. Nunca me he ido con un mal corte.', 5, '2025-01-10T10:00:00.000Z'),
('gr-004', 'Yoan Trucker', 'Gran servicio y excelente corte de pelo. Fade limpio, personal profesional y ambiente muy amigable. 100% recomendado.', 5, '2025-01-15T10:00:00.000Z'),
('gr-005', 'eric alejandro castro', '¡La mejor experiencia en una barbería – Gracias, Mario! He estado en muchas barberías, pero ninguna se compara a esta. Mario es un verdadero artista.', 5, '2025-01-20T10:00:00.000Z'),
('gr-006', 'ERIC ZENICKI', 'Si buscas un barbero de primera en el suroeste de Florida, no busques más que a Yoandry (Station #4) en Next Level. Es un verdadero profesional que ofrece un servicio excelente a precios muy razonables. La barbería está impecable.', 5, '2025-01-25T10:00:00.000Z'),
('gr-007', 'Kelvin Gomez', 'Jhonny es, sin duda, uno de los mejores barberos que he conocido. Realmente escucha lo que quieres y ofrece un corte limpio y nítido cada vez. Muy amigable, profesional y se toma su tiempo.', 5, '2025-02-01T10:00:00.000Z'),
('gr-008', 'Darwin', 'Si buscas un gran corte a un precio excelente, necesitas ver al mejor barbero… ¡¡¡Yoni!!!! Lo más duro de Next Level…..Yoni!!!', 5, '2025-02-05T10:00:00.000Z'),
('gr-009', 'Brian Pease', 'Yoandry en station #4 me atendió muy bien y me ofreció un excelente servicio al cliente. Me hizo sentir muy bien con mi corte nuevo.', 5, '2025-02-10T10:00:00.000Z'),
('gr-010', 'Kay''s Life', 'Ve a que te corte con Yoandry. Servicio y corte de primera. Muy recomendado.', 5, '2025-02-15T10:00:00.000Z'),
('gr-011', 'Maikel Sanchez', 'La barbería de Mario es una joya escondida. Mario es un maestro en su oficio, ofreciendo asesoramiento experto y cortes impecables. La barbería tiene un ambiente acogedor y amigable.', 5, '2025-02-20T10:00:00.000Z'),
('gr-012', 'Yosmen Hector Simon', 'Solía vivir en Miami donde había varias opciones para cortes de pelo. Me mudé a Cape Coral y temía no encontrar un lugar donde mi barbero pudiera cumplir con mis altas expectativas. Next Level superó todo.', 5, '2025-02-25T10:00:00.000Z'),
('gr-013', 'Dillon Enck', 'Por mucho, la mejor barbería de la ciudad. He probado varios barberos aquí, pero ahora siempre voy con Yonis, hace un gran trabajo y sabe exactamente lo que quiero cada vez.', 5, '2025-03-01T10:00:00.000Z'),
('gr-014', 'Aida Profet', 'He ido a un par de barberías en el área, esta es la única donde he visto a los barberos limpiar sus máquinas, y eso es muy importante para mí ya que tengo un niño pequeño. Yorjandri le ha cortado el pelo a mi hijo varias veces.', 5, '2025-03-05T10:00:00.000Z'),
('gr-015', 'Teddy Diaz', 'Me senté en la silla 6. Le expliqué el corte al barbero. Me miró como si fuera difícil y luego hizo un corte mediocre. El fade no estaba bien difuminado. Me cobró $5 más que el precio en el letrero. Booo.', 1, '2025-03-08T10:00:00.000Z'),
('gr-016', 'Chris Simons', 'Mi experiencia aquí fue notable. El negocio es nuevo. Muy moderno y limpio. El barbero fue muy educado y profesional. Se aseguró de entender claramente lo que quería.', 5, '2025-03-10T10:00:00.000Z'),
('gr-017', 'Phil F.', 'Un lugar realmente agradable y limpio. Miguel me atendió muy bien.', 5, '2025-03-12T10:00:00.000Z'),
('gr-018', 'Leslie Dean', 'Después de vivir en Cape por 6 años, finalmente encontré una excelente barbería. Fui a Next Level hoy y no podría estar más feliz.', 5, '2025-03-14T10:00:00.000Z'),
('gr-019', 'Jon and Mel', 'Entré sin cita, nunca había estado antes. Servicio increíble, muy limpio y profesional. Me senté inmediatamente con Yoni, me hizo un low fade perfecto y perfilado de barba. Yoni es un barbero de fuego.', 5, '2025-03-16T10:00:00.000Z'),
('gr-020', 'Derek P', 'Buscaba una barbería más cerca de casa y la encontré. Hice una cita a través de Booksy. Me cortó el pelo Allan, fue muy bueno y detallista. Muy limpia y moderna.', 5, '2025-03-18T10:00:00.000Z'),
('gr-021', 'Jason Hope', 'Siempre voy aquí para ver a Yoandry, es el mejor. Siempre hace un gran trabajo, es consistente y se asegura de que sus clientes se vayan felices.', 5, '2025-03-20T10:00:00.000Z'),
('gr-022', 'Osvany Serrano', 'Si no estás feliz con tu corte de pelo, es porque no has ido a Next Level Barbershop. Pásate y busca a mi chico Mario, él te va a dejar muy bien.', 5, '2025-03-22T10:00:00.000Z'),
('gr-023', 'Danara Alonso', 'Excelentes barberos, muy profesionales y amables. El ambiente es muy tranquilo y el servicio es espectacular. Lo recomiendo 100%.', 5, '2025-03-24T10:00:00.000Z'),
('gr-024', 'Kevin DePiano', 'Gran corte, gran experiencia. ¡Yoandry fue genial!', 5, '2025-03-26T10:00:00.000Z'),
('gr-025', 'Chad Gard', 'Me afeitaron toda la barba el día antes de la boda de mi hija. Luego me echaron porque estaba molesto. Este lugar es basura caliente.', 1, '2025-03-28T10:00:00.000Z'),
('gr-026', 'Jacob Grafmyre', 'Primera vez en esta barbería y me cortó Yorjandi. Servicio muy profesional y muy orientado a los detalles. Ven aquí y no te decepcionará.', 5, '2025-04-01T10:00:00.000Z'),
('gr-027', 'Vanessa Ramos', 'Acabo de llevar a mi hijo de 20 meses para su primer corte de barbero. ¡Lo hicieron muy bien! Jugaron con él para que se sintiera cómodo y el corte fue perfecto.', 5, '2025-04-05T10:00:00.000Z'),
('gr-028', 'Steve Policastri', 'Mal corte dos veces seguidas, $40 por barba y corte. En lugar de hacer un buen trabajo, siempre usan spray de relleno en lugar de prestar atención para hacer un buen corte desde el principio. Perezosos.', 2, '2025-04-08T10:00:00.000Z'),
('gr-029', 'Kevin Gomez', 'Nuevo en la ciudad y encontré este lugar convenientemente ubicado al lado de Publix. Entré y me cortó Allan. Gran comunicación y excelente corte. Muy talentoso. Volveré.', 5, '2025-04-10T10:00:00.000Z'),
('gr-030', 'Greg Harder', 'Nueva barbería en el centro comercial de Publix. Allan me hizo un excelente corte. Muy profesional y orientado a los detalles. Lo recomendaría.', 5, '2025-04-12T10:00:00.000Z'),
('gr-031', 'Nancy V', 'Mi esposo ha ido a que lo corte Miguel desde antes de que empezáramos a salir (hace 9 años) y siempre hace un trabajo increíble.', 5, '2025-04-14T10:00:00.000Z'),
('gr-032', 'Avelino Mendoza', 'Me atendieron temprano, gran atención al detalle. Yorjandy es excelente en su oficio. Tienes un nuevo cliente. ¡Gracias!', 5, '2025-04-16T10:00:00.000Z'),
('gr-033', 'Rocio Zermeno', 'Miguel es un gran barbero, ha cortado el pelo de mi esposo y mis dos hijos adolescentes durante los últimos 18 años. ¡Grandiosos cortes!', 5, '2025-04-18T10:00:00.000Z'),
('gr-034', 'Parker Brown', 'Fue una gran experiencia y me dieron un GRAN corte, uno de los mejores que he tenido en mi vida. Definitivamente recomiendo venir aquí.', 5, '2025-04-20T10:00:00.000Z'),
('gr-035', 'William Huber', 'Jeffrey fue increíble. Corte de pelo y perfilado de barba: el mejor trabajo de barba que he tenido. Muy recomendado.', 5, '2025-04-22T10:00:00.000Z'),
('gr-036', 'Lee Cichon', '¡Excelente barbería! Servicio amable y excelente. Allan hizo un gran trabajo con mi corte.', 5, '2025-04-24T10:00:00.000Z'),
('gr-037', 'Anna Dorosh', 'Llevé a mi hijo a ver a Jeffrey. Gran servicio y atención al detalle. Definitivamente lo recomiendo.', 5, '2025-04-26T10:00:00.000Z'),
('gr-038', 'Tiffany Chobrda', '¡Gran corte y servicio! Yoandry fue genial con mi hijo.', 5, '2025-04-28T10:00:00.000Z'),
('gr-039', 'Carla', 'Recientemente llevé a mi sobrino y me impresionó lo bien que fue la experiencia.', 5, '2025-05-01T10:00:00.000Z'),
('gr-040', 'Ronald Perez', 'Me corté con Allan ayer y fue genial, corte fresco y muy eficiente.', 5, '2025-05-03T10:00:00.000Z'),
('gr-041', 'yudith lopez', 'Muy bonito lugar. Lindo y limpio. Excelentes barberos. Ubicación muy conveniente.', 5, '2025-05-05T10:00:00.000Z'),
('gr-042', 'Fidel Alvarez', 'Excelente servicio con Yoandry en Stage #4.', 5, '2025-05-07T10:00:00.000Z'),
('gr-043', 'Kenneth Rourk', 'Salí con un corte impecable, gran barbería.', 5, '2025-05-09T10:00:00.000Z'),
('gr-044', 'Andrea K. Simpson', '¡Hicieron un gran trabajo con mis dos hijos!', 5, '2025-05-11T10:00:00.000Z'),
('gr-045', 'Aneudy Reyes', 'Mcdonis 100%', 5, '2025-05-13T10:00:00.000Z'),
('gr-046', 'Brandon Osorio', 'La mejor barbería de la ciudad, muy recomendada.', 5, '2025-05-15T10:00:00.000Z'),
('gr-047', 'Howie DuPrie, Jr.', 'Muy buen servicio de barbería.', 5, '2025-05-17T10:00:00.000Z'),
('gr-048', 'Misael Cruz', 'Gran corte de Jhonny J!', 5, '2025-05-19T10:00:00.000Z'),
('gr-049', 'Alain G. Betancourt', 'Muy buena atención y un buen recorte de barba.', 5, '2025-05-21T10:00:00.000Z'),
('gr-050', 'luis munoz', 'Siempre rápido y gran trabajo.', 5, '2025-05-23T10:00:00.000Z'),
('gr-051', 'Diego Hernandez', 'Muy buena experiencia, los trabajadores son muy amables.', 5, '2025-05-25T10:00:00.000Z'),
('gr-052', 'A Flores', 'Cortes limpios a un precio limpio.', 5, '2025-05-27T10:00:00.000Z'),
('gr-053', 'duilio gonzalez', 'Gran servicio.', 5, '2025-05-29T10:00:00.000Z'),
('gr-054', 'Leo Lantigua', 'Gran barbería. Me encanta la ubicación. Miguel hizo un gran trabajo preparándome para el fin de semana. La barbería es moderna y bonita por dentro.', 5, '2025-06-01T10:00:00.000Z'),
('gr-055', 'Josue Hernández', 'Cada vez que voy a la barbería salgo más que satisfecho. Jony es un barbero con excelente técnica, atención y dedicación a cada corte.', 5, '2025-06-05T10:00:00.000Z'),
('gr-056', 'Hansel Leyva', 'Uno de los mejores servicios de corte que he tenido, lo recomiendo mucho. Es de los mejores, su nombre es Jhony.', 5, '2025-06-10T10:00:00.000Z'),
('gr-057', 'JCN Plumbing', 'Después de probar muchas barberías, finalmente encontré esta y no podría estar más feliz. Lo primero que noté fue el ambiente: música a un volumen perfecto, algo que agradezco.', 5, '2025-06-15T10:00:00.000Z'),
('gr-058', 'Dayron Oduardo', '¡Gran barbería! Estoy muy satisfecho con el servicio y el gran trabajo de mi barbero, Jonny.', 5, '2025-06-20T10:00:00.000Z'),
('gr-059', 'Anabek Crespo', 'Excelente servicio, el lugar es muy bonito, limpio, muy profesional.', 5, '2025-06-25T10:00:00.000Z'),
('gr-060', 'Fernando Borroto', 'Mario brinda un excelente servicio; estoy muy contento. Es muy paciente y siempre está para complacer al cliente. El mejor, sin duda.', 5, '2025-07-01T10:00:00.000Z'),
('gr-061', 'Jorge Figueroa', 'La mejor barbería de la ciudad. Me he cortado el pelo con Miguel durante 15 años. También corta el de mi hijo. Te garantizo que te encantará tu corte 100%.', 5, '2025-07-05T10:00:00.000Z'),
('gr-062', 'Reinier Godinez', 'Mis hijos y yo nos hemos cortado el pelo en esta barbería y el servicio es muy bueno y los barberos son muy buenos. Me cortó Yoni, es muy profesional.', 5, '2025-07-10T10:00:00.000Z'),
('gr-063', 'Andira Regalado Oslé', 'Me encanta el servicio de esta barbería, el estilo del salón y la higiene. Recomiendo encarecidamente hacerse cliente habitual.', 5, '2025-07-15T10:00:00.000Z'),
('gr-064', 'Yonel Calderón', 'Excelente servicio, el mejor en Cape Coral. Servicio de primera, y Yoandry está actualizado en sus cortes. Llegué y pedí station #4.', 5, '2025-07-20T10:00:00.000Z'),
('gr-065', 'Katia Pérez Pérez', '¡Excelente servicio! El corte de mi bebé es hermoso. Gracias a todo el equipo, especialmente a Pablo.', 5, '2025-07-25T10:00:00.000Z'),
('gr-066', 'Jose Javier Soto Aguirre', 'Yoandry. El mejor barbero. Sin duda. Stage 4.', 5, '2025-08-01T10:00:00.000Z'),
('gr-067', 'Ernesto Garcia', 'Excelente servicio con barberos profesionales, total comodidad y la mejor atención al cliente.', 5, '2025-08-05T10:00:00.000Z'),
('gr-068', 'Jose Silva', 'Profesional y un gran ambiente. Ernesto es excelente y se toma su tiempo.', 5, '2025-08-10T10:00:00.000Z'),
('gr-069', 'Dennys Vega', 'Recomiendo mucho este lugar, son muy profesionales y estoy más que satisfecho con mi corte de pelo.', 5, '2025-08-15T10:00:00.000Z'),
('gr-070', 'rainiero gonzalez', 'Yojandri no sabe cortar el pelo, totalmente inútil.', 1, '2025-08-18T10:00:00.000Z'),
('gr-071', 'Dario Morón clavijo', 'El mejor sin duda. Muy recomendado. Mario.', 5, '2025-08-20T10:00:00.000Z'),
('gr-072', 'Bryan Rojas', 'La mejor experiencia con Mario, ¡el mejor de los mejores y el más duro!', 5, '2025-08-25T10:00:00.000Z'),
('gr-073', 'Jonyweb Herramientas', 'Muy buena barbería, muy recomendable.', 5, '2025-09-01T10:00:00.000Z'),
('gr-074', 'Miguel Angel Hdez Otero', 'El mejor de los mejores.', 5, '2025-09-05T10:00:00.000Z'),
('gr-075', 'Yiniet Ali', 'Estuve muy satisfecho con su servicio, quedé encantado.', 5, '2025-09-10T10:00:00.000Z'),
('gr-076', 'Sandra Martin', 'Excelente servicio.', 5, '2025-09-15T10:00:00.000Z'),
('gr-077', 'Дмитрий Бушуев', 'Great barbershop.', 5, '2025-09-20T10:00:00.000Z'),
('gr-078', 'Alejandro Tovar', 'Muy bueno.', 5, '2025-09-25T10:00:00.000Z'),
('gr-079', 'Yadira', 'Excelente.', 5, '2025-09-30T10:00:00.000Z');
